#!/usr/bin/env python3
import re
import math
import requests
from param import n, e, c

try:
    import gmpy2
    def modinv(a, m):
        return int(gmpy2.invert(a, m))
except Exception:
    def egcd(a, b):
        if b == 0:
            return (a, 1, 0)
        g, x1, y1 = egcd(b, a % b)
        return (g, y1, x1 - (a // b) * y1)
    def modinv(a, m):
        g, x, _ = egcd(a, m)
        if g != 1:
            raise ValueError("not invertible")
        return x % m

URL = "http://crypto.csaw.io/rsa/decrypt"
K = 256


def extract_flag(data: bytes):
    m = re.search(rb"csawctf\{[^}\n\r]*\}", data)
    return m.group(0).decode(errors="ignore") if m else None


def oracle_decrypt(block: bytes):
    r = requests.post(URL, data=block, timeout=10)
    return r.status_code, r.content


def printable_preview(b: bytes, lim=220):
    return ''.join(chr(x) if 32 <= x <= 126 else '.' for x in b[:lim])


def main():
    c_int = int.from_bytes(c, 'big')
    print(f"[+] n bits = {n.bit_length()}, ciphertext bytes = {len(c)}")
    print(f"[+] c_int computed")

    candidate_s = [2, 3, 5, 7] + list(range(2, 51))
    seen = set()

    for s in candidate_s:
        if s in seen:
            continue
        seen.add(s)
        if math.gcd(s, n) != 1:
            print(f"[-] s={s} not coprime with n, skipping")
            continue

        c_prime = (c_int * pow(s, e, n)) % n
        c_prime_bytes = c_prime.to_bytes(K, 'big')

        try:
            status, out = oracle_decrypt(c_prime_bytes)
        except Exception as ex:
            print(f"[-] s={s} request failed: {ex}")
            continue

        if status != 200:
            print(f"[-] s={s} oracle HTTP {status}, len={len(out)}")
            continue

        m_prime_bytes = out
        if len(m_prime_bytes) != K:
            # try to normalize in case service strips leading zeros
            if len(m_prime_bytes) < K:
                m_prime_bytes = m_prime_bytes.rjust(K, b'\x00')
            else:
                print(f"[-] s={s} unexpected oracle length {len(m_prime_bytes)}")
                continue

        m_prime = int.from_bytes(m_prime_bytes, 'big')
        s_inv = modinv(s, n)
        m = (m_prime * s_inv) % n

        m_full = m.to_bytes(K, 'big')
        m_strip = m_full.lstrip(b'\x00')

        flag = extract_flag(m_full) or extract_flag(m_strip)

        print(f"[+] s={s} success, preview(full)={printable_preview(m_full)}")

        if not flag:
            for txt in [
                m_full.decode('utf-8', errors='ignore'),
                m_strip.decode('utf-8', errors='ignore'),
                m_full.decode('latin1', errors='ignore'),
                m_strip.decode('latin1', errors='ignore'),
            ]:
                m2 = re.search(r"csawctf\{[^}\n\r]*\}", txt)
                if m2:
                    flag = m2.group(0)
                    break

        if flag:
            print("[+] FLAG FOUND:", flag)
            idx = m_full.find(flag.encode())
            if idx == -1:
                idx = m_strip.find(flag.encode())
                src = m_strip
                which = 'stripped'
            else:
                src = m_full
                which = 'full'
            if idx != -1:
                snippet = src[max(0, idx-16):idx+len(flag)+16]
                print(f"[+] snippet ({which}):", snippet)
            return

    print("[-] No flag found in s range")


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
import re
import math
import requests
from param import n, e, c


def invmod(a, m):
    try:
        return pow(a, -1, m)
    except TypeError:
        # very old python fallback
        t, newt = 0, 1
        r, newr = m, a % m
        while newr != 0:
            q = r // newr
            t, newt = newt, t - q * newt
            r, newr = newr, r - q * newr
        if r > 1:
            raise ValueError('not invertible')
        if t < 0:
            t += m
        return t


def scan_flag(blob: bytes):
    m = re.search(rb"csawctf\{[^}]*\}", blob)
    return m.group(0).decode(errors='ignore') if m else None


def pretty_attempts(m_bytes: bytes):
    stripped = m_bytes.lstrip(b"\x00")
    print("full block (first 96 hex):", m_bytes[:96].hex())
    print("lstrip(\\x00) length:", len(stripped))
    print("lstrip preview:", stripped[:200])
    for enc in ("utf-8", "latin1"):
        try:
            s = stripped.decode(enc, errors='ignore')
        except Exception:
            s = ""
        print(f"decoded({enc}) preview:", repr(s[:200]))


def main():
    url = "http://crypto.csaw.io/rsa/decrypt"
    k = 256
    c_int = int.from_bytes(c, "big")

    print(f"[+] modulus bytes: {k}, c bytes: {len(c)}")

    found = None
    proof = None

    for s in list(range(2, 51)):
        if math.gcd(s, n) != 1:
            continue

        c_prime = (c_int * pow(s, e, n)) % n
        c_prime_bytes = c_prime.to_bytes(k, "big")

        try:
            r = requests.post(url, data=c_prime_bytes, timeout=10)
        except Exception as ex:
            print(f"[-] s={s}: request failed: {ex}")
            continue

        if r.status_code != 200:
            print(f"[-] s={s}: HTTP {r.status_code}")
            continue

        if b"Forbidden" in r.content or b"Illegal" in r.content:
            print(f"[-] s={s}: oracle rejected ciphertext")
            continue

        m_prime_bytes = r.content
        if len(m_prime_bytes) != k:
            # normalize if server returned shorter due to leading zeros
            if len(m_prime_bytes) < k:
                m_prime_bytes = m_prime_bytes.rjust(k, b"\x00")
            else:
                m_prime_bytes = m_prime_bytes[-k:]

        m_prime = int.from_bytes(m_prime_bytes, "big")
        s_inv = invmod(s, n)
        m = (m_prime * s_inv) % n
        m_bytes = m.to_bytes(k, "big")

        print(f"[+] s={s}: got decrypt response, scanning...")
        pretty_attempts(m_bytes)

        # scan binary full + stripped + decoded strings
        flag = scan_flag(m_bytes) or scan_flag(m_bytes.lstrip(b"\x00"))
        if not flag:
            txt1 = m_bytes.decode("utf-8", errors="ignore")
            txt2 = m_bytes.decode("latin1", errors="ignore")
            m1 = re.search(r"csawctf\{[^}]*\}", txt1)
            m2 = re.search(r"csawctf\{[^}]*\}", txt2)
            if m1:
                flag = m1.group(0)
            elif m2:
                flag = m2.group(0)

        if flag:
            found = flag
            idx = m_bytes.find(flag.encode())
            if idx != -1:
                proof = m_bytes[max(0, idx-16):idx+len(flag)+16]
            else:
                proof = m_bytes.lstrip(b"\x00")[:120]
            print("\n[FLAG]", found)
            print("[PROOF BYTES]", proof)
            break

    if not found:
        print("[-] Flag not found in s=2..50")
    else:
        print("[+] Done")


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
import re
import math
import requests
from param import n, e, c

try:
    import gmpy2
    def modinv(a, m):
        return int(gmpy2.invert(a, m))
except Exception:
    def egcd(a, b):
        if b == 0:
            return (a, 1, 0)
        g, x1, y1 = egcd(b, a % b)
        return (g, y1, x1 - (a // b) * y1)
    def modinv(a, m):
        g, x, _ = egcd(a, m)
        if g != 1:
            raise ValueError('no inverse')
        return x % m

URL = 'http://crypto.csaw.io/rsa/decrypt'
K = 256


def oracle_decrypt_block(ct_block: bytes):
    r = requests.post(URL, data=ct_block, timeout=10)
    if r.status_code != 200:
        return None, f'HTTP {r.status_code}'
    if len(r.content) == 256:
        return r.content, None
    return None, r.content.decode(errors='ignore')


def scan_flag(data: bytes):
    m = re.search(rb'csawctf\{[^\}]{0,200}\}', data)
    return m.group(0).decode(errors='ignore') if m else None


def show_variants(m_int):
    full = m_int.to_bytes(K, 'big')
    stripped = full.lstrip(b'\x00')
    print('[*] Full block (hex, first 96B):', full[:96].hex())
    print('[*] Stripped (hex, first 96B):   ', stripped[:96].hex())
    for enc in ('utf-8', 'latin1'):
        for bufname, buf in [('full', full), ('stripped', stripped)]:
            s = buf.decode(enc, errors='ignore')
            print(f'[*] Decode {bufname}/{enc} sample: {s[:200]!r}')
    return full, stripped


def main():
    c_int = int.from_bytes(c, 'big')
    print(f'[*] n bits={n.bit_length()}  e={e}')

    # Try s=2 first, then fallback range 2..50
    s_candidates = [2] + [x for x in range(2, 51) if x != 2]

    for s in s_candidates:
        if math.gcd(s, n) != 1:
            print(f'[-] s={s}: gcd(s,n)!=1, skipping')
            continue

        c_prime = (c_int * pow(s, e, n)) % n
        c_prime_bytes = c_prime.to_bytes(K, 'big')

        m_prime_bytes, err = oracle_decrypt_block(c_prime_bytes)
        if m_prime_bytes is None:
            print(f'[-] s={s}: oracle rejected ({err})')
            continue

        m_prime = int.from_bytes(m_prime_bytes, 'big')
        s_inv = modinv(s, n)
        m = (m_prime * s_inv) % n

        print(f'[+] s={s}: oracle decrypt success, unblinded plaintext candidate')
        full, stripped = show_variants(m)

        for buf in (full, stripped):
            f = scan_flag(buf)
            if f:
                print(f'[FLAG] {f}')
                snippet = buf[max(0, buf.find(b"csawctf{")-16):buf.find(b"}")+1]
                print(f'[SNIPPET] {snippet!r}')
                return

        # also scan decoded strings just in case
        for enc in ('utf-8', 'latin1'):
            s_full = full.decode(enc, errors='ignore')
            mobj = re.search(r'csawctf\{[^\}]{0,200}\}', s_full)
            if mobj:
                print(f'[FLAG] {mobj.group(0)}')
                return

    print('[!] Flag not found in tested s range.')


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
import re
import math
import requests

from param import n, e, c

try:
    import gmpy2
    def modinv(a, m):
        return int(gmpy2.invert(a, m))
except Exception:
    def modinv(a, m):
        return pow(a, -1, m)

URL = "http://crypto.csaw.io/rsa/decrypt"
K = 256


def oracle_decrypt(ct_bytes: bytes):
    r = requests.post(URL, data=ct_bytes, timeout=15)
    return r.content


def extract_flag(blob: bytes):
    m = re.search(rb"csawctf\{[^}]+\}", blob)
    if m:
        return m.group(0).decode(errors="ignore")
    return None


def scan_and_print(m_bytes: bytes):
    variants = [
        ("full", m_bytes),
        ("lstrip", m_bytes.lstrip(b"\x00")),
    ]

    for name, vb in variants:
        print(f"\n[{name}] len={len(vb)}")
        print(vb)
        for enc in ("utf-8", "latin1"):
            try:
                s = vb.decode(enc, errors="ignore")
            except Exception:
                continue
            print(f"[{name} decode {enc}] {s}")
            f = extract_flag(vb) or extract_flag(s.encode())
            if f:
                return f, vb
    return None, None


def main():
    c_int = int.from_bytes(c, "big")
    print(f"n bits={n.bit_length()} c bytes={len(c)}")

    found_flag = None
    proof = None

    # Start with requested preference and fallback loop.
    s_candidates = [2] + [x for x in range(2, 51) if x != 2]

    for s in s_candidates:
        if math.gcd(s, n) != 1:
            continue

        c_prime = (c_int * pow(s, e, n)) % n
        c_prime_bytes = c_prime.to_bytes(K, "big")

        resp = oracle_decrypt(c_prime_bytes)

        if b"Forbidden" in resp or len(resp) != K:
            print(f"s={s}: rejected or unexpected response len={len(resp)} content={resp[:80]!r}")
            continue

        m_prime = int.from_bytes(resp, "big")
        s_inv = modinv(s, n)
        m = (m_prime * s_inv) % n
        m_bytes = m.to_bytes(K, "big")

        print(f"\n=== s={s} successful ===")
        flag, blob = scan_and_print(m_bytes)
        if flag:
            found_flag = flag
            proof = blob
            break

    if found_flag:
        print("\n[+] FLAG FOUND:", found_flag)
        snippet_match = re.search(rb"csawctf\{[^}]+\}", proof)
        if snippet_match:
            print("[+] proof snippet:", snippet_match.group(0))
    else:
        print("[-] No flag found in tested s range.")


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
import re
import requests
import gmpy2
from param import n, e, c

URL = "http://crypto.csaw.io/rsa/decrypt"
K = 256


def bytes_preview(b: bytes, n=120):
    return repr(b[:n])


def find_flag(data: bytes):
    m = re.search(rb"csawctf\{[^}]*\}", data)
    return m.group(0).decode(errors="ignore") if m else None


def decode_attempts(data: bytes):
    out = []
    for enc, err in [("utf-8", "ignore"), ("latin1", "ignore")]:
        try:
            out.append((enc, data.decode(enc, errors=err)))
        except Exception:
            pass
    return out


def oracle_decrypt(block: bytes):
    r = requests.post(URL, data=block, timeout=10)
    return r


def main():
    c_int = int.from_bytes(c, "big")
    print(f"[*] modulus bytes={K}, ciphertext bytes={len(c)}")

    tried = []
    recovered = None

    for s in range(2, 51):
        if gmpy2.gcd(s, n) != 1:
            continue

        c_prime = (c_int * pow(s, e, n)) % n
        c_prime_bytes = int(c_prime).to_bytes(K, "big")

        r = oracle_decrypt(c_prime_bytes)
        if r.status_code != 200:
            print(f"[-] s={s}: http {r.status_code}")
            continue

        m_prime_bytes = r.content
        if len(m_prime_bytes) != K:
            # likely forbidden or error text
            print(f"[-] s={s}: non-{K}-byte response: {m_prime_bytes[:80]!r}")
            continue

        m_prime = int.from_bytes(m_prime_bytes, "big")
        s_inv = int(gmpy2.invert(s, n))
        m = (m_prime * s_inv) % n
        m_bytes_full = int(m).to_bytes(K, "big")
        m_bytes_strip = m_bytes_full.lstrip(b"\x00")

        tried.append((s, m_bytes_full, m_bytes_strip))

        flag = find_flag(m_bytes_full) or find_flag(m_bytes_strip)
        if not flag:
            for _, text in decode_attempts(m_bytes_full):
                m2 = re.search(r"csawctf\{[^}]*\}", text)
                if m2:
                    flag = m2.group(0)
                    break
        if not flag:
            for _, text in decode_attempts(m_bytes_strip):
                m2 = re.search(r"csawctf\{[^}]*\}", text)
                if m2:
                    flag = m2.group(0)
                    break

        print(f"[+] s={s} worked. full_preview={bytes_preview(m_bytes_full)}")
        if flag:
            recovered = (s, flag, m_bytes_full, m_bytes_strip)
            break

    if recovered:
        s, flag, fullb, stripb = recovered
        print("\n=== RECOVERED ===")
        print(f"s = {s}")
        print(f"flag = {flag}")
        print(f"full block preview: {bytes_preview(fullb, 220)}")
        print(f"stripped preview: {bytes_preview(stripb, 220)}")
    else:
        print("[!] No flag found in s=2..50. Showing first 3 candidates previews.")
        for i, (s, fullb, stripb) in enumerate(tried[:3]):
            print(f"--- s={s} ---")
            print(f"full: {bytes_preview(fullb, 220)}")
            print(f"stripped: {bytes_preview(stripb, 220)}")


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
import re
import math
import requests
from param import n, e, c

try:
    import gmpy2
    def modinv(a, m):
        return int(gmpy2.invert(a, m))
except Exception:
    def egcd(a, b):
        if b == 0:
            return (a, 1, 0)
        g, x1, y1 = egcd(b, a % b)
        return (g, y1, x1 - (a // b) * y1)
    def modinv(a, m):
        g, x, _ = egcd(a, m)
        if g != 1:
            raise ValueError('not invertible')
        return x % m

URL = "http://crypto.csaw.io/rsa/decrypt"


def scan_flag(blob: bytes):
    m = re.search(rb"csawctf\{[^}]*\}", blob)
    return m.group(0).decode(errors="ignore") if m else None


def recover_with_s(s: int, c_int: int):
    c_prime = (c_int * pow(s, e, n)) % n
    payload = c_prime.to_bytes(256, 'big')
    r = requests.post(URL, data=payload, timeout=10)
    if r.status_code != 200:
        raise RuntimeError(f"HTTP {r.status_code}")
    m_prime_bytes = r.content
    m_prime = int.from_bytes(m_prime_bytes, 'big')
    s_inv = modinv(s, n)
    m = (m_prime * s_inv) % n
    m_full = m.to_bytes(256, 'big')
    m_strip = m_full.lstrip(b'\x00')
    return {
        's': s,
        'resp_len': len(m_prime_bytes),
        'm_full': m_full,
        'm_strip': m_strip,
        'utf8': m_strip.decode('utf-8', errors='ignore'),
        'latin1': m_strip.decode('latin1', errors='ignore'),
    }


def main():
    c_int = int.from_bytes(c, 'big')
    print(f"[*] n_bits={n.bit_length()} c_len={len(c)}")
    found = None

    for s in range(2, 51):
        if math.gcd(s, n) != 1:
            continue
        try:
            res = recover_with_s(s, c_int)
        except Exception as ex:
            print(f"[!] s={s} failed: {ex}")
            continue

        cand = scan_flag(res['m_full']) or scan_flag(res['m_strip'])
        print(f"[*] s={s} resp_len={res['resp_len']} strip_len={len(res['m_strip'])}")
        if cand:
            found = (cand, res)
            break

    if found:
        flag, res = found
        print(f"[+] FLAG: {flag}")
        snippet = re.search(rb"csawctf\{[^}]*\}", res['m_full'])
        if snippet:
            print(f"[+] proof(full): {snippet.group(0)!r}")
        else:
            snippet = re.search(rb"csawctf\{[^}]*\}", res['m_strip'])
            print(f"[+] proof(strip): {snippet.group(0)!r}")
    else:
        print("[-] flag not found in s=2..50")


if __name__ == '__main__':
    main()
